    47→/// Module data for TechBuildingBehavior
    48→#[derive(Debug, Clone)]
    49→pub struct TechBuildingBehaviorModuleData {
    50→    /// FXList to play when building is owned and updated
    51→    pub pulse_fx: Option<Arc<FXList>>,
    52→    /// How frequently to play the pulse FX
    53→    pub pulse_fx_rate: UnsignedInt,
    54→}
    55→
    56→impl TechBuildingBehaviorModuleData {
    57→    pub fn new() -> Self {
    58→        Self {
    59→            pulse_fx: None,
    60→            pulse_fx_rate: 0,
    61→        }
    62→    }
    63→}
